import{c as l,Q as e,j as s,m as i}from"./chunks/framework.BXc4yaFE.js";const h=JSON.parse('{"title":"团队内的 skills 管理和维护的一点经验分享（以 codex cli 用的 .agents/skills 目录为例）：","description":"","frontmatter":{"title":"团队内的 skills 管理和维护的一点经验分享（以 codex cli 用的 .agents/skills 目录为例）：","author":"宝玉（@dotey）","date":"2026-04-02T00:00:00.000Z","source":"https://x.com/dotey/status/2039762741284553033","type":"tweet"},"headers":[],"relativePath":"research/tweets/2026-04-02-@dotey-553033.md","filePath":"research/tweets/2026-04-02-@dotey-553033.md","lastUpdated":1779894392000}'),o={name:"research/tweets/2026-04-02-@dotey-553033.md"};function a(r,t,n,d,k,c){return e(),s("div",null,[...t[0]||(t[0]=[i('<h1 id="团队内的-skills-管理和维护的一点经验分享-以-codex-cli-用的-agents-skills-目录为例" tabindex="-1">团队内的 skills 管理和维护的一点经验分享（以 codex cli 用的 .agents/skills 目录为例）： <a class="header-anchor" href="#团队内的-skills-管理和维护的一点经验分享-以-codex-cli-用的-agents-skills-目录为例" aria-label="Permalink to &quot;团队内的 skills 管理和维护的一点经验分享（以 codex cli 用的 .agents/skills 目录为例）：&quot;">​</a></h1><ol><li>Git 管理是一定要的。 版 — @dotey</li></ol><p><strong>來源</strong>：<a href="https://x.com/dotey/status/2039762741284553033" target="_blank" rel="noreferrer">https://x.com/dotey/status/2039762741284553033</a><strong>作者</strong>：宝玉（@dotey） <strong>發布日期</strong>：2026-04-02 <strong>收錄日期</strong>：2026-04-26 <strong>類型</strong>：推文 <strong>統計</strong>：630 likes · 136 retweets · 778 bookmarks · 68,287 views</p><hr><h2 id="全文" tabindex="-1">全文 <a class="header-anchor" href="#全文" aria-label="Permalink to &quot;全文&quot;">​</a></h2><p>团队内的 skills 管理和维护的一点经验分享（以 codex cli 用的 .agents/skills 目录为例）：</p><ol><li><p>Git 管理是一定要的。 版本控制太重要了，而且 Skills 都是 Markdown 和脚本文件，天然适合 Git。</p></li><li><p>用好 Symlink。 不要把 Skills 整个拷贝到 .agents/skills，而是通过 Symlink 直接链接到原始 Skills 的 Repo。</p></li></ol><p>好处有两个：一是版本控制更干净；二是使用中遇到问题，Agent 定位后可以直接在 Repo 里改，改完就能 Review 提 PR。</p><p>我日常维护 baoyu-skills 就是这么干的，用的时候发现问题，让 Agent 在当前会话改，改的就是 Repo 本身，流程非常顺。</p><p>主要的坑是 Windows 下好像不支持 Symlink，另外首次配置稍麻烦（可以让 Agent 帮你操作）。</p><ol start="3"><li><p>Skills 的编辑优先让 Agent 来。 改完走 Git 提 PR，这就是最好的协作和发布流程。</p></li><li><p>验证确实不太好做。 脚本部分可以写单元测试，Skill 的 Markdown 部分只能靠平时积累的测试集，大部分还得人工。 但配合 Git 的版本管理，快速迭代反而更现实：不怕改出问题，出了问题根据 commit history 快速定位，或者直接回滚。</p></li><li><p>最后提醒一下：大部分 Skills 应该跟着项目走（放项目目录下的 .agents/skills），不要放全局（~/.agents/skills）。 即使是渐进式加载，meta 信息累积起来也会占不小的上下文空间。</p></li></ol><hr><h2 id="研究摘要" tabindex="-1">研究摘要 <a class="header-anchor" href="#研究摘要" aria-label="Permalink to &quot;研究摘要&quot;">​</a></h2><p><strong>TL;DR</strong>：分享 Skills 團隊管理的 5 個實踐：Git 版本控制必要、用 Symlink 連接到原始 Repo（不是複製）、優先讓 Agent 編輯 Skills 後 PR、測試主要靠人工加測試集、大部分 Skills 應放在專案層級而非全局。</p><h3 id="核心論點" tabindex="-1">核心論點 <a class="header-anchor" href="#核心論點" aria-label="Permalink to &quot;核心論點&quot;">​</a></h3><ol><li><strong>Git + Symlink 是核心工作流</strong>：不把 Skills 複製到 <code>.agents/skills</code>，而是用 symlink 指向原始 Repo — 版本控制更乾淨，Agent 定位問題後直接在 Repo 改並 PR</li><li><strong>Agent 協助維護 Skills</strong>：遇到問題讓 Agent 在當前 session 直接改 Repo，改完就可 review 提 PR — 人機協作形成閉環</li><li><strong>驗證仍然是痛點</strong>：腳本部分可以單元測試，Markdown 部分只能靠人工 + 測試集累積；快速迭代 + Git 回滾比追求完美更現實</li><li><strong>專案層級優先</strong>：大部分 Skills 應放 <code>.agents/skills</code>（專案目錄），不放 <code>~/.agents/skills</code>（全局）— 即使漸進式加載，meta 累積也佔 context</li><li><strong>Windows Symlink 坑</strong>：Windows 不支援 Symlink（或需要特殊權限），是重要的跨平台限制</li></ol><h3 id="關鍵數據-工具" tabindex="-1">關鍵數據 / 工具 <a class="header-anchor" href="#關鍵數據-工具" aria-label="Permalink to &quot;關鍵數據 / 工具&quot;">​</a></h3><ul><li>實踐者：dotey (宝玉)，個人維護 baoyu-skills Repo</li><li>適用工具：Codex CLI 的 <code>.agents/skills</code> 目錄（與 Claude Code <code>.claude/skills/</code> 同概念）</li><li>630 likes · 778 bookmarks · 68,287 views</li><li>Windows 問題：Symlink 在 Windows 需要管理員權限或開發者模式</li></ul><h3 id="批判性觀察" tabindex="-1">批判性觀察 <a class="header-anchor" href="#批判性觀察" aria-label="Permalink to &quot;批判性觀察&quot;">​</a></h3><ul><li>Git + Symlink 方案的複雜度比直接複製高，對新手門檻較高</li><li>「讓 Agent 改 Repo 然後 PR」的流程假設 Agent 了解 Git workflow，需要 CLAUDE.md 明確規定 PR 流程</li><li>「大部分 Skills 應跟著專案走」的建議與 skill-authoring.md 的 progressive disclosure 設計一致，可相互驗證</li><li>cc-workspace 的 <code>.claude/skills/</code> 已符合建議的專案層級模式</li></ul><hr><h2 id="評分" tabindex="-1">評分 <a class="header-anchor" href="#評分" aria-label="Permalink to &quot;評分&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>分數</th><th>說明</th></tr></thead><tbody><tr><td>A. Workspace 可行動性 (30%)</td><td>7/10</td><td>Git + Symlink 工作流可直接應用於 cc-workspace Skills 管理，與現有 repo 結構整合</td></tr><tr><td>B. 創新性 (20%)</td><td>7/10</td><td>Symlink 而非複製的設計決策，以及 Agent 協助維護 Skills 的閉環流程，有獨到洞見</td></tr><tr><td>C. 證據品質 (20%)</td><td>7/10</td><td>第一手實踐分享，有具體工作流和已知坑（Windows），可信度高</td></tr><tr><td>D. 技術深度 (15%)</td><td>6/10</td><td>概念清晰但缺乏具體命令範例，Windows Symlink 坑值得記錄</td></tr><tr><td>E. 泛化性 (15%)</td><td>8/10</td><td>適用所有多人團隊或個人管理多個 Skills 的情境</td></tr><tr><td><strong>加權總分</strong></td><td><strong>7.10/10</strong></td><td></td></tr></tbody></table><p><strong>整合決策</strong>：Rule <strong>理由</strong>：Skills 管理的 Git + Symlink 原則和「Skills 放專案層級」的明確建議可補充 cc-workspace 的 skill-authoring.md 或新增 skills-governance.md 規則。</p>',24)])])}const p=l(o,[["render",a]]);export{h as __pageData,p as default};
